import { Drawer, List, ListItemButton, ListItemText } from "@mui/material";
import { useNavigate } from "react-router-dom";

export default function Sidebar() {
  const navigate = useNavigate();

  // âś… safe role (lowercase)
  const role = localStorage.getItem("role")?.toLowerCase();

  // đź”Ą ROLE BASED MENUS (UPDATED)
  const menu = {
    superadmin: [
      { name: "Dashboard", path: "/superadmin" },
      { name: "Create Admin", path: "/superadmin/create-admin" },
    ],

    admin: [
      { name: "Dashboard", path: "/admin" },
      { name: "Projects", path: "/admin/projects" },
      { name: "Create Member", path: "/admin/create-member" }, // đź”Ą added
    ],

    member: [
      { name: "Dashboard", path: "/member/dashboard" }, // đź”Ą fixed path
      { name: "Create User", path: "/member/create-user" }, // đź”Ą updated
    ],

    user: [
      { name: "Dashboard", path: "/user/dashboard" }, // đź”Ą fixed
    ],
  };

  return (
    <Drawer
      variant="permanent"
      sx={{
        width: 220,
        flexShrink: 0,
        "& .MuiDrawer-paper": {
          width: 220,
          boxSizing: "border-box",
        },
      }}
    >
      <List sx={{ width: 220 }}>
        {menu[role]?.map((item) => (
          <ListItemButton key={item.name} onClick={() => navigate(item.path)}>
            <ListItemText primary={item.name} />
          </ListItemButton>
        ))}

        {/* âť— fallback if role missing */}
        {!menu[role] && (
          <ListItemText
            primary="No access"
            sx={{ textAlign: "center", mt: 2 }}
          />
        )}
      </List>
    </Drawer>
  );
}
